  ('generalpolice-3218f787-moex-00258', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-111-7ac5ce32', 'sub-generalpolice-3218f787-05', NULL, 'single_choice', '社會學家涂爾幹（EmileDurkheim）曾提出「脫序」（anomie）此一概念，此概念最主要在說明 什麼？', '["指人類在追求理性化的過程中，會將人們帶入一個「鐵的牢籠」（ironcage）", "說明在資本主義體系的生產過程中，工人與產品間關係的斷裂", "指在現代化過程中，傳統價值及規範逐漸瓦解，因而造成民眾失去方向和不安", "它是指整體社會成員所共享的成套信念"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:31+00:00", "source_pdf_sha1": "246f08078638", "answer_pdf_sha1": "833358795d8d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "302", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會學與社會工作", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00259', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-111-7ac5ce32', 'sub-generalpolice-3218f787-05', NULL, 'single_choice', '新制度論（neo-institutionalism）學者 DiMaggio 與 Powell（1983）提出組織的「制度趨同主義 （institutionalisomorphism）」，下列何者不屬於「制度趨同主義」中的機制類型？', '["強制趨同機制", "行動趨同機制", "模仿趨同機制", "規範趨同機制"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:31+00:00", "source_pdf_sha1": "246f08078638", "answer_pdf_sha1": "833358795d8d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "302", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會學與社會工作", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00260', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-111-7ac5ce32', 'sub-generalpolice-3218f787-05', NULL, 'single_choice', '下列對於「文化」此概念之相關說明，何者正確？', '["文化的社會生成，係指文化是人類因應生存需要，或滿足個體與集體的好奇與慾望，而創造出 來的結果", "文化相對論係指文化的價值與規範並未具有明顯的時間和空間特性，所以各民族均可擁有相同 的價值和規範", "種族中心論係將他人的行為、價值、規範和信仰視為是唯一合理與正當的形式", "文化帝國主義係指受到在地化的影響，各國積極建立屬於自己文化特色的產品，並銷售到世界 其他國家"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:31+00:00", "source_pdf_sha1": "246f08078638", "answer_pdf_sha1": "833358795d8d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "302", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會學與社會工作", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00261', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-111-7ac5ce32', 'sub-generalpolice-3218f787-05', NULL, 'single_choice', '下列何者不是社會學家們對現代家庭中「家務分工」議題所提出的理論解釋？', '["資源交換論", "新家務分工論", "父權社會對女性的剝奪", "性別展示與實踐"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:31+00:00", "source_pdf_sha1": "246f08078638", "answer_pdf_sha1": "833358795d8d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "302", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會學與社會工作", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00262', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-111-7ac5ce32', 'sub-generalpolice-3218f787-05', NULL, 'single_choice', '下列關於「社會階層化」的說明何者正確？', '["社會階層化是促進社會進步的動力", "社會階層化是提升經濟發展的重要動力", "社會階層化是促進民主政治發展的重要動力", "韋伯（MaxWeber）認為社會階級、地位、權力是進行社會階層化研究時的三個重要探討面向"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:31+00:00", "source_pdf_sha1": "246f08078638", "answer_pdf_sha1": "833358795d8d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "302", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會學與社會工作", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00263', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-111-7ac5ce32', 'sub-generalpolice-3218f787-05', NULL, 'single_choice', '下列有關社會學對婚姻制度的描述何者正確？', '["當前社會對於現代婚姻制度的社會規範有逐漸增強的趨勢", "婚姻制度化的歷程與離婚率不斷上升有著密切的關係", "女性地位的提升是「個體化婚姻模式」興起的重要影響因素", "少子化是造成婚姻去制度化的重要原因"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:31+00:00", "source_pdf_sha1": "246f08078638", "answer_pdf_sha1": "833358795d8d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "302", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會學與社會工作", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00264', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-111-7ac5ce32', 'sub-generalpolice-3218f787-05', NULL, 'single_choice', '下列何者不是用來解釋「社會運動」發生的理論觀點？', '["資源動員理論", "政治過程論", "新社會運動論", "父權主義論"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:31+00:00", "source_pdf_sha1": "246f08078638", "answer_pdf_sha1": "833358795d8d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "302", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會學與社會工作", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00265', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-111-7ac5ce32', 'sub-generalpolice-3218f787-05', NULL, 'single_choice', '下列陳述何者是由符號互動論（symbolicinteractionalism）學者米德（GeorgeHerbertMead）所提 出的理論觀點？', '["他將社會控制定義為「主我」對「客我」的支配", "他提出「鏡中自我」的觀點，來說明父母如何影響孩童發展出與他人互動的能力", "他認為人的自我（self）會隨著時間而發展，並需要經歷「玩耍（playstage）」及「遊戲（game stage）」二個關鍵階段", "他用「印象管理」的概念來說明，在與他人互動時會使用不同方法來控制在不同社會情境中所 欲呈現的形象"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:31+00:00", "source_pdf_sha1": "246f08078638", "answer_pdf_sha1": "833358795d8d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "302", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會學與社會工作", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL)
